UPDATE eval_answer_52
SET content = #{item.selfFeedback}, 
    score = #{item.selfScore}
WHERE question_id = #{item.questionId}
  AND mapping_id = (
        SELECT id FROM eval_target_mapping_52 
        WHERE evaluatee_no = #{empNo} 
        AND CAST(step AS VARCHAR) = 'SELF'
  )

UPDATE eval_answer_52
SET content = #{item.firstFeedback}, 
    score = #{item.firstScore}
WHERE question_id = #{item.questionId}
  AND mapping_id = (
        SELECT id FROM eval_target_mapping_52 
        WHERE evaluatee_no = #{empNo} 
        AND CAST(step AS VARCHAR) = 'FIRST'
  )
